#ifndef __NEAREST_NEIGHBOR__
#define __NEAREST_NEIGHBOR__

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <sys/time.h>
#include <omp.h>

#define REC_LENGTH 49 

typedef struct latLong
{
  float lat;
  float lng;
} LatLong;

typedef struct record
{
  char recString[REC_LENGTH];
  float distance;
} Record;

typedef struct RecordNode {
    Record rec;
    struct RecordNode* next;
} RecordNode;

typedef struct LatLongNode {
    LatLong loc;
    struct LatLongNode* next;
} LatLongNode;

char *data_folder;

int loadData(char *filename, RecordNode** recordsHead, LatLongNode** locationsHead, int* numRecords);
void findLowest(RecordNode* recordsHead, float *distances, int numRecords, int topN);
int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d);
void printUsage();

float *OpenMpFindNearestNeighbors(
	int numRecords,
	LatLongNode* locationsHead,float lat,float lng);

int main(int argc, char *argv[]) {
  RecordNode* recordsHead = NULL;
  LatLongNode* locationsHead = NULL;
  float *recordDistances;

  int i;

  char filename[100];
  int resultsCount=10,quiet=0,timing=0,platform=-1,device=-1;
  float lat=0.0,lng=0.0;
  int numRecords = 0;

  if (parseCommandline(argc, argv, filename,&resultsCount,&lat,&lng,
                     &quiet, &timing, &platform, &device)) {
    printUsage();
    return 0;
  }

  numRecords = loadData(filename, &recordsHead, &locationsHead, &numRecords);

  if (!quiet) {
    printf("Number of records: %d\n",numRecords);
    printf("Finding the %d closest neighbors.\n",resultsCount);
  }

  if (numRecords < resultsCount) resultsCount = numRecords;

  struct timeval tv_total_start, tv_total_end;
  if (timing) gettimeofday(&tv_total_start, NULL);

  recordDistances = OpenMpFindNearestNeighbors(numRecords,locationsHead,lat,lng);

  if (timing) {
    gettimeofday(&tv_total_end, NULL);
    double elapsed = (tv_total_end.tv_sec - tv_total_start.tv_sec) * 1000.0 + (tv_total_end.tv_usec - tv_total_start.tv_usec) / 1000.0;
    printf("Total: %f\n", elapsed);
  }

  findLowest(recordsHead,recordDistances,numRecords,resultsCount);

  if (!quiet) {
    RecordNode* curr = recordsHead;
    for(i=0; i < resultsCount && curr != NULL; i++, curr = curr->next) {
      printf("%s --> Distance=%f\n",curr->rec.recString,curr->rec.distance);
    }
  }
  free(recordDistances);

  // Free linked lists
  RecordNode* rcurr = recordsHead;
  while(rcurr) {
    RecordNode* tmp = rcurr;
    rcurr = rcurr->next;
    free(tmp);
  }
  LatLongNode* lcurr = locationsHead;
  while(lcurr) {
    LatLongNode* tmp = lcurr;
    lcurr = lcurr->next;
    free(tmp);
  }

  return 0;
}

float *OpenMpFindNearestNeighbors(
	int numRecords,
	LatLongNode* locationsHead,float lat,float lng) {

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Failed to allocate distances array\n");
        exit(1);
    }

    #pragma omp parallel for
    for (int i = 0; i < numRecords; i++) {
        // Traverse linked list to ith element
        LatLongNode* node = locationsHead;
        for(int j=0; j<i; j++) {
            node = node->next;
        }
        LatLong latLong = node->loc;
        distances[i] = sqrtf((lat - latLong.lat)*(lat - latLong.lat) + (lng - latLong.lng)*(lng - latLong.lng));
    }

    return distances;
}

int loadData(char *filename, RecordNode** recordsHead, LatLongNode** locationsHead, int* numRecords){
    FILE   *flist,*fp;
	int    i=0;
	char dbname[64], db_fullname[128];
	int recNum=0;

    flist = fopen(filename, "r");
	if (!flist) {
        fprintf(stderr, "Error opening file list: %s\n", filename);
        exit(1);
    }
	while(fscanf(flist, "%s\n", dbname) == 1) {
        sprintf(db_fullname, "%s/%s", data_folder, dbname);
        fp = fopen(db_fullname, "r");
        if(!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while(1){
            Record record;
            LatLong latLong;
            if (!fgets(record.recString, REC_LENGTH, fp)) break;
            int c = fgetc(fp); // consume newline or separator
            if (feof(fp)) break;

            char substr[6];

            for(i=0;5 > i;i++) substr[i] = *(record.recString+i+28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;5 > i;i++) substr[i] = *(record.recString+i+33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            // Append to linked lists
            RecordNode* newRecordNode = (RecordNode*)malloc(sizeof(RecordNode));
            if (!newRecordNode) {
                fprintf(stderr, "Memory allocation failed\n");
                exit(1);
            }
            newRecordNode->rec = record;
            newRecordNode->next = NULL;
            if (*recordsHead == NULL) {
                *recordsHead = newRecordNode;
            } else {
                RecordNode* tmp = *recordsHead;
                while(tmp->next) tmp = tmp->next;
                tmp->next = newRecordNode;
            }

            LatLongNode* newLocNode = (LatLongNode*)malloc(sizeof(LatLongNode));
            if (!newLocNode) {
                fprintf(stderr, "Memory allocation failed\n");
                exit(1);
            }
            newLocNode->loc = latLong;
            newLocNode->next = NULL;
            if (*locationsHead == NULL) {
                *locationsHead = newLocNode;
            } else {
                LatLongNode* tmp = *locationsHead;
                while(tmp->next) tmp = tmp->next;
                tmp->next = newLocNode;
            }

            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    *numRecords = recNum;
    return recNum;
}

void findLowest(RecordNode* recordsHead,float *distances,int numRecords,int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  // Convert linked list to array for easier swapping
  Record* recArray = (Record*)malloc(numRecords * sizeof(Record));
  if (!recArray) {
      fprintf(stderr, "Memory allocation failed\n");
      exit(1);
  }
  RecordNode* curr = recordsHead;
  for(i=0; i<numRecords && curr != NULL; i++, curr=curr->next) {
      recArray[i] = curr->rec;
  }

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = recArray[i];
    recArray[i] = recArray[minLoc];
    recArray[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    recArray[i].distance = distances[i];
  }

  // Copy back to linked list
  curr = recordsHead;
  for(i=0; i<numRecords && curr != NULL; i++, curr=curr->next) {
      curr->rec = recArray[i];
  }

  free(recArray);
}

int parseCommandline(int argc, char *argv[], char* filename,int *r,float *lat,float *lng,
                     int *q, int *t, int *p, int *d){
    int i;
    if (2 > argc) return 1; 
    strncpy(filename,argv[1],100);
    char flag;

    for(i=1;argc > i;i++) {
      if ('-' == argv[i][0]) {
        flag = argv[i][1];
          switch (flag) {
            case 'r': 
              i++;
              *r = atoi(argv[i]);
              break;
            case 'l': 
              if ('a' == argv[i][2]) {
                *lat = atof(argv[i+1]);
              }
              else {
                *lng = atof(argv[i+1]);
              }
              i++;
              break;
            case 'h': 
              return 1;
              break;
            case 'q': 
              *q = 1;
              break;
            case 't': 
              *t = 1;
              break;
            case 'p': 
              i++;
              *p = atoi(argv[i]);
              break;
            case 'd': 
              i++;
              *d = atoi(argv[i]);
              break;
            case 'f': 
              i++;
              data_folder = argv[i];
              break;
        }
      }
    }
    if ((0 <= *d && 0 > *p) || (0 <= *p && 0 > *d)) 
      return 1;
    return 0;
}

void printUsage(){
  printf("Nearest Neighbor Usage\n");
  printf("\n");
  printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
  printf("\n");
  printf("example:\n");
  printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
  printf("\n");
  printf("filename     the filename that lists the data input files\n");
  printf("-r [int]     the number of records to return (default: 10)\n");
  printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
  printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
  printf("\n");
  printf("-h, --help   Display the help file\n");
  printf("-q           Quiet mode. Suppress all text output.\n");
  printf("-t           Print timing information.\n");
  printf("\n");
  printf("-p [int]     Choose the platform (must choose both platform and device)\n");
  printf("-d [int]     Choose the device (must choose both platform and device)\n");
  printf("\n");
  printf("\n");
  printf("Notes: 1. The filename is required as the first parameter.\n");
  printf("       2. If you declare either the device or the platform,\n");
  printf("          you must declare both.\n\n");
}

#endif
